        {
          id: 3,
          name: 'Corn',
          category: 'Grains',
          price: 1800,
          unit: 'Quintal',
          change: +30,
          changePercent: 1.69,
          market: 'Noida Mandi',
          quality: 'Yellow',
          arrival: 280,
          icon: 'corn'
        },
        {
          id: 4,
          name: 'Chana Dal',
          category: 'Pulses',
          price: 5200,
          unit: 'Quintal',
          change: +100,
          changePercent: 1.96,
          market: 'Delhi Mandi',
          quality: 'Bold',
          arrival: 180,
          icon: 'food'
        },
        {
          id: 5,
          name: 'Moong',
          category: 'Pulses',
          price: 7800,
          unit: 'Quintal',
          change: -150,
          changePercent: -1.89,
          market: 'Gurgaon Mandi',
          quality: 'Bold',
          arrival: 120,
          icon: 'food'
        },
        {
          id: 6,
          name: 'Mustard',
          category: 'Oilseeds',
          price: 4500,
          unit: 'Quintal',
          change: +80,
          changePercent: 1.81,
          market: 'Ghaziabad Mandi',
          quality: 'Black',
          arrival: 200,
          icon: 'flower'
        },
        {
          id: 7,
          name: 'Potato',
          category: 'Vegetables',
          price: 1200,
          unit: 'Quintal',
          change: +60,
          changePercent: 5.26,
          market: 'Agra Mandi',
          quality: 'Jyoti',
          arrival: 800,
          icon: 'food-variant'
        },
        {
          id: 8,
          name: 'Onion',
          category: 'Vegetables',
          price: 2800,
          unit: 'Quintal',
          change: -120,
          changePercent: -4.11,
          market: 'Nashik Mandi',
          quality: 'Medium',
          arrival: 650,
          icon: 'food-variant'
        },
        {
          id: 9,
          name: 'Tomato',
          category: 'Vegetables',
          price: 3200,
          unit: 'Quintal',
          change: +200,
          changePercent: 6.67,
          market: 'Pune Mandi',
          quality: 'Hybrid',
          arrival: 400,
          icon: 'food-variant'
        },
        {
          id: 10,
          name: 'Mango',
          category: 'Fruits',
          price: 4000,
          unit: 'Quintal',
          change: +150,
          changePercent: 3.90,
          market: 'Lucknow Mandi',
